import{_ as o,o as r,c as s,a as i,b as n,w as d,d as a,e,r as c}from"./app.f1423e2d.js";const l={},m=a(`<h1 id="arthas-properties" tabindex="-1"><a class="header-anchor" href="#arthas-properties" aria-hidden="true">#</a> Arthas Properties</h1><p>The <code>arthas.properties</code> file is in the arthas directory.</p><ul><li>If it is automatically downloaded arthas, the directory is under <code>~/.arthas/lib/3.x.x/arthas/</code></li><li>If it is a downloaded complete package, under the decompression directory of arthas</li></ul><h2 id="supported-configuration-items" tabindex="-1"><a class="header-anchor" href="#supported-configuration-items" aria-hidden="true">#</a> Supported configuration items</h2><div class="custom-container warning"><p class="custom-container-title">WARNING</p><p>Note that the configuration must be <code>camel case</code>, which is different from the <code>-</code> style of spring boot. Only the spring boot application supports both <code>camel case</code> and <code>-</code> style configuration.</p></div><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>#arthas.config.overrideAll=true
arthas.telnetPort=3658
arthas.httpPort=8563
arthas.ip=127.0.0.1

# seconds
arthas.sessionTimeout=10800

#arthas.appName=demoapp
#arthas.tunnelServer=ws://127.0.0.1:7777/ws
#arthas.agentId=mmmmmmyiddddd
#arthas.commandLocations=/opt/arthas/ext-command.jar,/opt/arthas/ext-commands
# Arthas will also try to load *.jar from \${arthas.home}/commands if the directory exists
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>If the configuration of <code>arthas.telnetPort</code> is -1, the telnet port will not be listened. <code>arthas.httpPort</code> is similar.</li><li>If you configure <code>arthas.telnetPort</code> to 0, then random listen telnet port, you can find the random port log in <code>~/logs/arthas/arthas.log</code>. <code>arthas.httpPort</code> is similar.</li></ul><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>If you want to prevent multiple arthas port conflicts on a machine. It can be configured as a random port, or configured as -1, and use arthas through the tunnel server.</p></div><h3 id="disable-specify-commands" tabindex="-1"><a class="header-anchor" href="#disable-specify-commands" aria-hidden="true">#</a> disable specify commands</h3><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>since 3.5.2</p></div><p>Such as configuration:</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>arthas.disabledCommands=stop,dump
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>It can also be configured on the command line: <code>--disabled-commands stop,dump</code>.</p><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>By default, arthas-spring-boot-starter will disable the <code>stop</code> command.</p></div><h3 id="load-external-commands" tabindex="-1"><a class="header-anchor" href="#load-external-commands" aria-hidden="true">#</a> Load external commands</h3><p>You can load external command jars when Arthas starts:</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>arthas.commandLocations=/opt/arthas/ext-command.jar,/opt/arthas/ext-commands
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>Each entry can be a jar file path or a directory path, separated by commas.</li><li>Directory entries only scan <code>*.jar</code> in the current directory and do not recurse.</li><li>If <code>\${arthas.home}/commands</code> exists, Arthas also tries to load <code>*.jar</code> from that directory at startup. Explicit <code>arthas.commandLocations</code> are loaded first, then the default directory.</li><li>The external jar should expose a <code>CommandResolver</code> via <code>META-INF/services/com.taobao.arthas.core.shell.command.CommandResolver</code>.</li><li>Arthas keeps built-in commands first; when an external command conflicts with a built-in command name, the external command is skipped and a log is written.</li></ul><p>It can also be configured on the command line: <code>--command-locations &#39;/opt/arthas/ext-command.jar,/opt/arthas/ext-commands&#39;</code>.</p>`,19),h=e("For a complete external command development and loading example, see "),p=e("Load External Commands"),u=e("."),v=a('<h2 id="configured-order" tabindex="-1"><a class="header-anchor" href="#configured-order" aria-hidden="true">#</a> Configured order</h2><p>The order of configuration is: command line parameters &gt; System Env &gt; System Properties &gt; arthas.properties.</p><p>such as:</p><ul><li><code>./as.sh --telnet-port 9999</code> command line configuration will overwrite the default value <code>arthas.telnetPort=3658</code> in <code>arthas.properties</code>.</li><li>If the application itself sets system properties <code>arthas.telnetPort=8888</code>, it will override the default value <code>arthas.telnetPort=3658</code> in <code>arthas.properties</code>.</li></ul><p>If you want <code>arthas.properties</code> to have the highest order, you can configure <code>arthas.config.overrideAll=true</code>.</p>',5);function f(b,g){const t=c("RouterLink");return r(),s("div",null,[m,i("p",null,[h,n(t,{to:"/en/doc/external-command.html"},{default:d(()=>[p]),_:1}),u]),v])}const y=o(l,[["render",f],["__file","arthas-properties.html.vue"]]);export{y as default};
